const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
const BLOCK_OF_3_BASE_PREMIUM = 60;

const quotePremium = (items: Item[]): number => {
  const countsByType: Record<string, number> = {};
  for (const item of items) {
    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
  }
  let baseTotal = 0;
  for (const [type, count] of Object.entries(countsByType)) {
    if (COMPONENT_TYPES.has(type) && count === 3) {
      baseTotal += BLOCK_OF_3_BASE_PREMIUM;
    } else {
      baseTotal += BASE_PREMIUMS[type] * count;
    }
  }
  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};
